var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아이고야……. 한참 재밌어질 때였는데 더 못 움직이겠네.","JPN":"いたたたた……だいぶ盛り上がってきたのに、これ以上動けそうにないわ。","ENG":"Ow… This was just starting to get really fun, but I can't move a muscle now.","TWN":"哎唷喂呀……人家打得正開心呢，現在都不能動了啦！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"사지에 단순 골절 감지. 깁스를 한 상태에서도 지금처럼 날뛸 수 있을지 궁금하군요.","JPN":"手足に複数の単純骨折を感知。ギプスをした状態でも今のように暴れられるか気になりますね。","ENG":"Fractures detected in all limbs. I wonder if you'll still thrash about so wildly in a full body cast.","TWN":"感應到四肢骨，我很好奇在包著石膏的狀態下，你還能這麼活潑嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"하나는 남겨 주지. 이대로 돌아가면 난 잔혹한 고용주한테 속수무책으로 당할 거야. 흑흑.","JPN":"1か所くらいは残しといてよ。このまま戻ったら血も涙もないクライアントにボコボコにされちゃうもん、ぐすん。","ENG":"You could've left at least one limb intact. If I go back like this, I'll be helpless in front of my big jerk employer. *Sob*","TWN":"我跟你說，我這樣回去，就只能任殘忍的主人宰割，呵呵。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 상태로 잘도 떠드는군요. 통각 신경도 정상적으로 작동하는 휴먼이.","JPN":"そんな状態でもおしゃべりですね。痛覚神経も正常に作動するヒューマンのはずですが。","ENG":"Yet you seem to have no trouble running your mouth. Especially for a human whose sense of pain remains fully functional.","TWN":"人類，你的痛覺神經明明是正常的，但在這種狀態下你還是這麼聒噪呢。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"팔다리 좀 부러진 걸 가지고 뭘. 엄살 피우면서 간호 받을 생각에 벌써부터 행복한데?","JPN":"手足がちょっと折れただけで騒ぐも何もないもん。\\nあとで痛い痛いって訴えまくって介護してもらえると思ったらもう幸せ！","ENG":"Oh, it's just a few broken bones, that's all. The thought of getting all pampered in a hospital bed's getting me all giddy!","TWN":"是四肢骨折又不是嘴巴骨折，而且我只要哎個兩聲，就可以得到照顧，光想就覺得很幸福呢～"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"야호, 즐거운 농땡이 시간!","JPN":"やったあ、楽しいおサボりタイム！","ENG":"Woohoo! Now I can goof off legally!","TWN":"呀呵～可以光明正大摸魚囉～"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아흐앗파여!?","JPN":"いたたたっ！","ENG":"OUCH?!!","TWN":"唉唷好痛！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"펄떡거리지 마십시오. 치료 기간만 연장됩니다.","JPN":"ジタバタしないでください。治療期間が延びるだけです。","ENG":"Stop flailing about. You'll only extend the time it takes to heal.","TWN":"勸你動作還是不要太大，這樣只會增加休養時間。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아, 기다려. 호라이즌.","JPN":"ねえ、待ってよ、ホライズン！","ENG":"Wait, Horizon.","TWN":"喂，地平線，你等一下！"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"구급차 불러달라는 요청이라면 거절하겠습니다.","JPN":"救急車を呼んでほしいという要請ならお断りします。","ENG":"If you're about to ask me to call you an ambulance, I must decline.","TWN":"要我幫你叫救護車嗎？我拒絕。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에이, 내가 그런 부탁을 할 리가 없잖아.","JPN":"ええーアタシがそんなことを頼むわけないでしょ。","ENG":"Aw, come on. You know I'd never ask such a thing.","TWN":"哎唷～我怎麼可能拜託你那種事～"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇다면 왜 불러세웠습니까.","JPN":"それではなぜ呼び止めたのですか。","ENG":"Then why did you beckon me to wait?","TWN":"那你為何叫住我？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그 윌버란 아저씨 말이야, 네가 올 때를 대비해 거창한 환영식을 준비해 뒀어.","JPN":"そのウィルバーっておじさんね、アンタが来ると想定して、だいぶ派手な歓迎会を準備してるよ。","ENG":"That Wilbur guy… He's prepared one heck of a surprise party to welcome you.","TWN":"那個叫韋爾伯的叔叔，他準備了一個盛大的派對要歡迎你。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"내가 알려 줄 비상 통로를 따라가면 바로 뒤통수를 후려칠 수 있을 텐데, 어떡할래?","JPN":"アタシが知っている非常通路を使えば不意打ちを狙えると思うけど、どうする？","ENG":"I know an emergency exit route you could take to whack him from behind. How about it?","TWN":"我知道一個秘密通道，可以讓你殺他個措手不及，怎麼樣？你想知道嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"정면으로 갑니다.","JPN":"正面から行きます。","ENG":"I will face him from the front.","TWN":"我要正面迎戰。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"프레임을 너무 믿는 거 아니니? 출력이 예전 같지 않던데?","JPN":"フレームを過信しすぎじゃない？　出力が前に比べてだいぶ弱くなってたよ？","ENG":"Aren't you relying on that frame of yours a tad much? Your power output's not what it used to be.","TWN":"你會不會太高估那副軀殼？我看你的輸出好像不如以往？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 수금 중 채무자를 위협하기 위해 이런 복장을 입었습니다. 수금이 수월하기 때문이죠.","JPN":"私は集金中に債務者を脅すため、このような服装をしています。集金が容易になるからです。","ENG":"I've dressed myself in this fashion to intimidate my debtors during collection. It can help facilitate the collection, you see.","TWN":"我穿這身服裝是為了要恫嚇某些債務人，方便討債。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 어떤 휴먼들에게는 통하지 않더군요.","JPN":"しかし、あるヒューマンたちには通じませんでした。","ENG":"But it doesn't seem to work on certain humans.","TWN":"只是對某些人類似乎行不通。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그래? 예를 들면?","JPN":"そう？　例えば？","ENG":"Really? For example?","TWN":"是嗎？譬如說？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"믿는 구석이 있는 자들.","JPN":"当てにできるものがある者。","ENG":"People who believe they have an edge.","TWN":"有恃無恐的人。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그것이 주먹이든, 자본이든, 법의 허점이든. 자신이 믿는 것의 위력을 과대 평가하는 자들입니다.","JPN":"それが武力であれ、資本であれ、法律の隙間であれ。自身が当てにするものの力を過大評価する者たちのことです。","ENG":"Whether it be muscle, money, or legal loopholes… Such capabilities lead these people indulge in hubris.","TWN":"可能是拳頭，可能是錢財，也可能是法律漏洞，他們過於高估自以為有的籌碼。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그들은 상대를 때려눕히면 그만이라고, 매수하면 그만이라고, 고소하면 그만이라고 오해합니다.","JPN":"彼らは相手を叩きのめせば何とかなると、買収すれば何とかなると、告訴すれば何とかなると勘違いしています。","ENG":"They overestimate themselves thinking they can simply beat up, buy off, or sue their opponents.","TWN":"他們誤以為只要用拳頭打趴對方，或是用錢收買，或是提告，事情就會結束。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 커뮤니케이션은 오해를 바로잡는 것부터 시작해야 합니다.","JPN":"そしてコミュニケーションはそのような誤解を正すことから始めるべきです。","ENG":"True communication starts by shattering such misconceptions.","TWN":"因此和那種人的溝通，就必須從糾正他們的錯誤觀念開始。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"너 인생 정말 쓸데없이 힘들게 사는구나?","JPN":"アンタさ、本当に無駄に苦労する生き方してるね。","ENG":"You make your own life difficult, you know that?","TWN":"你的人生會不會太累？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"내 고용주랑 만나면 되게 재밌을 거 같아. 걔는 1년 내내 냉방병에 시달리거든.","JPN":"アタシのクライアントにぜひ会ってみてほしいわ。あの子は一年中冷房病に悩まされてるんだ。","ENG":"It'd be super interesting to see you meet my employer. She's shivering cold all year around.","TWN":"你和我的雇主見面的話一定會很有趣。她可是全年都受冷氣病所苦呢～"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"맞선은 사절입니다. 제 얼굴을 보고 싶어하는 선약들이 많이 밀려 있어서 말입니다.","JPN":"お見合いはお断りしています。私に直接会いたがっている先約が溜まっているので。","ENG":"I must decline any such arranged meetings. There's a long line of folks waiting to see me as it is.","TWN":"不勞你介紹，還有一堆人排隊想見我呢。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그럼 이번 맞선을 제대로 파토 내야겠다. 그래야 잔챙이들을 털어내지.","JPN":"じゃあ、次のお見合いを大失敗させるしかないか。邪魔者は排除しておかないとね。","ENG":"Then you'd better take care of this big appointment first. That should shorten the line with all the small fry too.","TWN":"那你這次會面一定要順利喔，這樣才能趕走其他蒼蠅。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"네. 그래서 정면으로 돌입할 계획입니다. 리벳.","JPN":"はい。なので正面から突入するつもりです、リベット。","ENG":"Precisely. That is why I will confront him face to face, Rivet.","TWN":"沒錯，所以我打算直搗黃龍，里維。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 윌버가, 그동안 믿고 있었던 모든 것들이 자신을 보호해 줄 수 없다는 사실을 증명한 뒤에.","JPN":"そして、ウィルバーがこれまで当てにしていたすべてのものは、彼の当てにならないという事実を証明した後に。","ENG":"Once I prove to Wilbur that everything he's been counting on to save his skin is useless…","TWN":"等我證明韋爾伯自以為可以保護自己的東西，其實並無法保護他之後，"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"전부 끝낼 겁니다.","JPN":"すべてを終わらせます。","ENG":"I'm going to end it all.","TWN":"一切就會落幕。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};